import sys,math
def is_prime(n:int)->bool:
    if n<2:
        return False
    limit=math.isqrt(n)
    for i in range(2,limit+1):
        if n%i==0:
            return False
    return True

def main():
    data=sys.stdin.read().strip().split()
    if not data:
        return
    it=iter(data)
    T=int(next(it))
    out=[]
    for _ in range(T):
        n=int(next(it))
        out.append('prime number' if is_prime(n) else 'non-prime number')
    sys.stdout.write('\n'.join(out))

if __name__=='__main__':
    main()

